mapper.select:
SELECT sp.id AS pref_id, sp.student_id, sp.year, sp.choice1_teacher_id, sp.choice2_teacher_id, sp.choice3_teacher_id, sp.file1_path, sp.file2_path, sp.file3_path, sp.status, sp.admin_assign_type, sp.admin_assigned_teacher_id, sp.created_time, sp.updated_time, s.student_no, s.name AS student_name, s.class_info, s.department_id, s.defense_type, s.title, s.summary, s.defense_year, s.advisor_teacher_id, t.name AS advisor_name FROM student_preference sp JOIN t_student s ON sp.student_id = s.id LEFT JOIN teacher t ON s.advisor_teacher_id = t.id WHERE sp.year = #{year}
AND sp.choice1_teacher_id = #{teacherId}
AND sp.choice2_teacher_id = #{teacherId}
AND sp.choice3_teacher_id = #{teacherId}
ORDER BY sp.updated_time DESC

SELECT s.id AS student_id, s.student_no, s.name AS student_name, s.class_info, s.department_id, s.defense_year, s.defense_type, s.advisor_teacher_id, adv.name AS advisor_name, sp.id AS pref_id, sp.choice1_teacher_id, sp.choice2_teacher_id, sp.choice3_teacher_id, sp.file1_path, sp.file2_path, sp.file3_path, sp.status, sp.admin_assign_type, sp.admin_assigned_teacher_id, t1.name AS choice1_teacher_name, t2.name AS choice2_teacher_name, t3.name AS choice3_teacher_name, ta.name AS admin_assigned_teacher_name FROM t_student s LEFT JOIN student_preference sp ON sp.student_id = s.id AND sp.year = s.defense_year LEFT JOIN teacher t1 ON sp.choice1_teacher_id = t1.id LEFT JOIN teacher t2 ON sp.choice2_teacher_id = t2.id LEFT JOIN teacher t3 ON sp.choice3_teacher_id = t3.id LEFT JOIN teacher ta ON sp.admin_assigned_teacher_id = ta.id LEFT JOIN teacher adv ON s.advisor_teacher_id = adv.id WHERE s.department_id = #{departmentId} AND s.defense_year = #{year}
AND s.advisor_teacher_id IS NULL
ORDER BY s.id DESC
